={{ 
  JSON.stringify((() => {
    // Relation fixe
    const fixedRelation = [{ id: '{{NOTION_ID_GENERIC_03}}' }];
  const Departement = $json["Département"];

    // Récupération et suppression des doublons
    const operateursIDs = Array.from(
      new Set($json.operateursIDs || [])
    ).map(id => ({ id }));

    // ID Responsable (one-way)
    const responsableId = $json["Responsable maintenance"];

    // Payload PATCH
    return {
      properties: {
        FUUU: { relation: fixedRelation },
        'ehl{': { relation: operateursIDs },
        pXDv: { relation: [{ id: responsableId }] },
        ':Rn_' : { relation: [{ id: Departement }] },
      }
    };
  })())
}}

