parameters.jsCode:
const allLogs = $input.all();

const consolidated = {
  workflow: allLogs[0].json._log?.workflow,
  startedAt: allLogs[0].json._log?.startedAt,
  finishedAt: new Date().toISOString(),
  ok: allLogs.reduce((sum, item) => sum + (item.json._log?.ok || 0), 0),
  ko: allLogs.reduce((sum, item) => sum + (item.json._log?.ko || 0), 0),

  // Récupération des nodes en échec (inchangé)
  failedNodes: allLogs.reduce((acc, item) => {
    if (item.json._hadError || item.json.error) {
      const nodeName = item.json._lastNode || item.json.error?.name || 'UnknownNode';
      acc[nodeName] = {
        error: true,
        message: item.json.error?.message || item.json._errMsg || 'Erreur inconnue'
      };
    }
    return acc;
  }, {}),

  // CORRECTION : Récupérer les vraies actions depuis _log.actions
  actions: allLogs.reduce((acc, item) => {
    // Récupérer les actions existantes dans _log.actions
    const existingActions = item.json._log?.actions || [];

    // Ajouter les actions existantes
    acc.push(...existingActions);

    // Si il y a une erreur globale sur cet item, ajouter une action d'erreur
    if (item.json._hadError || item.json.error) {
      const nodeName = item.json._lastNode || item.json.error?.name || 'UnknownNode';
      acc.push({
        node: nodeName,
        ok: false,
        msg: item.json.error?.message || item.json._errMsg || 'Erreur'
      });
    }

    return acc;
  }, [])
};

return [{ json: { _log: consolidated } }];

