const allBlocks = $input.all();
let maintenanceBlockId = null;

for (const item of allBlocks) {
  const block = item.json;
  if (block.type === 'heading_1' && block.content === 'Maintenance') {
    maintenanceBlockId = block.id;
    break;
  }
}

return [{
  json: {
    maintenanceBlockId: maintenanceBlockId,
    totalBlocks: allBlocks.length
  }
}];

