  "type": "heading_1",
  "heading_1": {
    "rich_text": [
      {
        "type": "text",
        "text": {
          "content": "Maintenance"
        }
      }
    ]
  }
};

// Préparer tous les blocs to_do
const todoBlocks = [];
for (const item of childBlocks) {
  const block = item.json;
  if (block.type === 'to_do') {
    todoBlocks.push({
      "type": "to_do",
      "to_do": {
        "rich_text": [
          {
            "type": "text",
            "text": {
              "content": block.content
            }
          }
        ],
        "checked": false
      }
    });
  }
}

return [{
  json: {
    taskPageId: taskPageId,
    maintenanceHeading: maintenanceHeading,
    todoBlocks: todoBlocks,
    totalTodos: todoBlocks.length
  }
}];

